import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async () => {
        if (!learnedPatternSource) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            /**
             * 🎯 MOTOR DE REPLICAÇÃO LITERAL (V4 - SEM INTERPRETAÇÃO)
             * Este prompt proíbe a IA de ser inteligente. Ela deve apenas mapear o que o humano fez.
             */
            const prompt = `VOCÊ É UM EXTRATOR DE PADRÕES ESTRUTURAIS. NÃO INTERPRETE. NÃO DEDUZA.
            Sua missão é gerar uma REGRA DE REPLICAÇÃO baseada em um único exemplo de correção manual.

            LINHA BRUTA (ORIGINAL):
            "${learnedPatternSource.originalRaw.join(' ; ')}"

            LINHA CORRIGIDA (GABARITO HUMANO):
            - Data: "${learnedPatternSource.corrected.date}"
            - Nome/Descrição: "${learnedPatternSource.corrected.description}"
            - Valor: "${learnedPatternSource.corrected.amount}"

            TAREFAS OBRIGATÓRIAS:
            1. Identifique em qual ÍNDICE (0 a N) da LINHA BRUTA estão os dados que o humano usou para preencher cada campo da LINHA CORRIGIDA.
            2. Analise o campo Nome/Descrição: Compare a string bruta da coluna correspondente com a string corrigida. 
               Liste TODAS as palavras, códigos ou símbolos que o humano APAGOU.
            3. Se uma palavra está no Bruto mas não no Corrigido, ela é uma "Palavra Ignorada".

            RESTRIÇÕES:
            - Se o valor no Corrigido não existir no Bruto, use -1 para o índice.
            - Retorne apenas a estrutura JSON conforme o contrato.
            - NUNCA invente palavras para ignorar que não estejam presentes na LINHA BRUTA fornecida.`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: prompt,
                config: { 
                    temperature: 0,
                    thinkingConfig: { thinkingBudget: 1000 },
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { 
                                type: Type.ARRAY, 
                                items: { type: Type.STRING },
                                description: "Lista de substrings removidas literalmente pelo humano" 
                            }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            if (result && typeof result.dateColumnIndex === 'number') {
                setActiveMapping((prev: any) => {
                    const newIgnored = Array.from(new Set([
                        ...(prev.ignoredKeywords || []), 
                        ...(result.ignoredKeywords || [])
                    ].map(k => k.trim().toUpperCase()))).filter(k => k.length >= 2);

                    return {
                        ...prev,
                        extractionMode: 'COLUMNS',
                        dateColumnIndex: result.dateColumnIndex,
                        descriptionColumnIndex: result.descriptionColumnIndex,
                        amountColumnIndex: result.amountColumnIndex,
                        ignoredKeywords: newIgnored
                    };
                });
                showToast("Padrão literal aprendido e aplicado.", "success");
            }
        } catch (e: any) {
            console.error("[PatternTeacher] Fail:", e);
            showToast("IA não conseguiu extrair o padrão literal da sua edição.", "error");
        } finally {
            setIsInferringMapping(false);
            setLearnedPatternSource(null);
        }
    }, [learnedPatternSource, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from '../types';
import { Logger } from "./monitoringService";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        return parsed.rows || parsed.transactions || (Array.isArray(parsed) ? parsed : fallback);
    } catch (e) {
        return fallback;
    }
};

