            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    extractionMode: { type: Type.STRING, description: "Fixar em 'COLUMNS' se houver delimitadores nítidos" },
                    dateColumnIndex: { type: Type.INTEGER },
