    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async (extractionMode: 'COLUMNS' | 'BLOCK' = 'COLUMNS') => {
        if (!learnedPatternSource) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            /**
             * 🎯 MOTOR DE REPLICAÇÃO LITERAL (V5 - SUPORTE A BLOCOS)
             */
            const isBlockMode = extractionMode === 'BLOCK';

            const prompt = isBlockMode 
            ? `VOCÊ É UM EXTRATOR DE PADRÕES POR FATIAMENTO DE BLOCO. NÃO USE COLUNAS.
            Sua missão é gerar um CONTRATO DE REPLICAÇÃO baseado nesta AMOSTRA DE BLOCO corrigida pelo humano.

            TEXTO DO BLOCO ORIGINAL:
            "${learnedPatternSource.originalRaw.join('\n')}"

            BLOCO EXTRAÍDO (GABARITO HUMANO):
            - Data: "${learnedPatternSource.corrected.date}"
            - Nome/Descrição: "${learnedPatternSource.corrected.description}"
            - Valor: "${learnedPatternSource.corrected.amount}"

            TAREFA:
            Crie uma regra de fatiamento. Identifique como o humano agrupou as linhas do bloco para extrair esses 3 campos. 
            O resultado deve ser um padrão que eu possa aplicar em outras partes do texto linear para extrair blocos idênticos.

            RESTRIÇÕES:
            - Não retorne índices de colunas.
            - Foque na ordem das strings e quebras de linha.`

            : `VOCÊ É UM EXTRATOR DE PADRÕES ESTRUTURAIS. NÃO INTERPRETE. NÃO DEDUZA.
            Sua missão é gerar uma REGRA DE REPLICAÇÃO baseada em um único exemplo de correção manual.

            LINHA BRUTA (ORIGINAL):
            "${learnedPatternSource.originalRaw.join(' ; ')}"

            LINHA CORRIGIDA (GABARITO HUMANO):
            - Data: "${learnedPatternSource.corrected.date}"
            - Nome/Descrição: "${learnedPatternSource.corrected.description}"
            - Valor: "${learnedPatternSource.corrected.amount}"

            TAREFAS OBRIGATÓRIAS:
            1. Identifique em qual ÍNDICE (0 a N) da LINHA BRUTA estão os dados que o humano usou para preencher cada campo da LINHA CORRIGIDA.
            2. Analise o campo Nome/Descrição: Compare a string bruta da coluna correspondente com a string corrigida. 
               Liste TODAS as palavras, códigos ou símbolos que o humano APAGOU.
            3. Se uma palavra está no Bruto mas não no Corrigido, ela é uma "Palavra Ignorada".`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: prompt,
                config: { 
                    temperature: 0,
                    thinkingConfig: { thinkingBudget: 1000 },
                    responseMimeType: "application/json",
                    responseSchema: isBlockMode ? {
                        type: Type.OBJECT,
                        properties: {
                            blockTemplate: { type: Type.STRING, description: "Descrição do contrato de fatiamento de bloco" },
                            extractionMode: { type: Type.STRING }
                        },
                        required: ["blockTemplate"]
                    } : {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            setActiveMapping((prev: any) => {
                if (isBlockMode) {
                    return {
                        ...prev,
                        extractionMode: 'BLOCK',
                        blockContract: result.blockTemplate,
                        // Limpa índices de coluna para evitar conflito
                        dateColumnIndex: -1,
                        descriptionColumnIndex: -1,
