import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { TypeResolver } from '../processors/TypeResolver';
import { NameResolver } from '../processors/NameResolver';
import { extractTransactionsWithModel } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V43 - RIGOR POR TIPO)
 * Implementa a aplicação determinística dos modelos treinados respeitando o MODO selecionado.
 */
export const ContractExecutor = {
    async apply(model: FileModel, adaptedInput: any, globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        if (!rawText.trim()) return [];

        const { mapping, parsingRules } = model;

        // 🧠 MODO BLOCO (LEITURA POR FATIAMENTO)
        // Ignora colunas e trata o texto como fluxo linear
        if (mapping.extractionMode === 'BLOCK') {
            console.log(`[ContractExecutor] 🧱 Aplicando Modo BLOCO para: ${model.name}`);

            const trainingContext = `
                ESTE É UM MODELO DE EXTRAÇÃO POR BLOCO.
                // Fix: Access blockContract from the destructured mapping object to ensure type safety
                CONTRATO APRENDIDO: ${mapping.blockContract || 'Replicação de estrutura de bloco linear'}
                EXEMPLO DE TREINO: \n${model.snippet?.substring(0, 3000)}
            `;

            // Fatiamento por volume para não estourar contexto, mantendo integridade dos blocos
            const lines = rawText.split(/\r?\n/);
            const CHUNK_SIZE = 150; 
            const chunks: string[] = [];
            for (let i = 0; i < lines.length; i += CHUNK_SIZE) {
                chunks.push(lines.slice(i, i + CHUNK_SIZE).join('\n'));
            }

            const batchPromises = chunks.map(async (textChunk, chunkIdx) => {
                try {
                    const aiResult = await extractTransactionsWithModel(textChunk, trainingContext);
                    return (aiResult || []).map((tx: any, idx: number) => ({
                        id: `exec-v43-block-${model.id}-${chunkIdx}-${idx}-${Date.now()}`,
                        date: tx.date,
                        description: tx.description,
                        rawDescription: tx.description,
                        amount: tx.amount,
                        originalAmount: String(tx.amount),
                        cleanedDescription: tx.description,
                        contributionType: tx.type || 'AUTO',
                        paymentMethod: tx.paymentMethod || 'OUTROS',
                        bank_id: model.id // Marca a origem para o hash
                    }));
                } catch (e) { return []; }
            });

            const resultsArray = await Promise.all(batchPromises);
            return resultsArray.flat();
        }

        // 🚀 MODO COLUNAS (DETERMINÍSTICO)
        const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);
        const results: Transaction[] = [];
        const currentYear = new Date().getFullYear();
        const modelKeywords = parsingRules?.ignoredKeywords || (mapping as any).ignoredKeywords || [];

        lines.forEach((line, idx) => {
            if (idx < (mapping.skipRowsStart || 0)) return;

            const cells = line.split(';'); 
            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";

            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, currentYear);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            if (isoDate && !isNaN(numAmount)) {
                const cleanedName = NameResolver.clean(rawDesc, modelKeywords, globalKeywords);

                results.push({
                    id: `exec-v43-col-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: cleanedName,
                    rawDescription: rawDesc,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: cleanedName,
                    contributionType: TypeResolver.resolveFromDescription(rawDesc),
                    paymentMethod: mapping.paymentMethodColumnIndex !== undefined && cells[mapping.paymentMethodColumnIndex] 
                        ? cells[mapping.paymentMethodColumnIndex] 
                        : TypeResolver.resolveFromDescription(rawDesc),
                    bank_id: model.id
                });
            }
        });

        return results;
    }
};

import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async (extractionMode: 'COLUMNS' | 'BLOCK' = 'COLUMNS') => {
        if (!learnedPatternSource) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            const isBlockMode = extractionMode === 'BLOCK';

            // PROMPT DE APRENDIZADO TÉCNICO (V6)
            const prompt = isBlockMode 
            ? `VOCÊ É UM ENGENHEIRO DE REVERSA DE DOCUMENTOS.
            O humano corrigiu uma extração de um PDF de fluxo contínuo. 
            Analise a relação entre o BLOCO BRUTO e a CORREÇÃO HUMANA.

            BLOCO BRUTO (Sequência de linhas):
            ${learnedPatternSource.originalRaw.map((l, i) => `L${i}: "${l}"`).join('\n')}

            CORREÇÃO GABARITO (O que o humano quer):
            - Data: "${learnedPatternSource.corrected.date}"
            - Nome/Descrição: "${learnedPatternSource.corrected.description}"
            - Valor: "${learnedPatternSource.corrected.amount}"

            SUA TAREFA:
            Crie uma "RECEITA DE GRUPAMENTO". 
            1. Quantas linhas brutas (L0, L1, L2...) compõem um único registro?
            2. Em qual "L" relativo está a Data?
            3. Em qual "L" relativo está o Nome?
            4. Em qual "L" relativo está o Valor?

            EXEMPLO DE RESPOSTA ESPERADA:
            "Cada registro tem 5 linhas. A Data e Valor estão na L0. O Nome está na L2. O CPF está na L3 e deve ser ignorado."

            RETORNE APENAS O JSON.`

            : `VOCÊ É UM EXTRATOR DE PADRÕES ESTRUTURAIS LATERAIS.
            Mapeie os índices de colunas (0 a N) baseando-se na correção:
            BRUTO: "${learnedPatternSource.originalRaw.join(' ; ')}"
            GABARITO: Data: "${learnedPatternSource.corrected.date}", Nome: "${learnedPatternSource.corrected.description}", Valor: "${learnedPatternSource.corrected.amount}"`;

            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: prompt,
                config: { 
                    temperature: 0,
                    responseMimeType: "application/json",
                    responseSchema: isBlockMode ? {
                        type: Type.OBJECT,
                        properties: {
                            blockRecipe: { type: Type.STRING, description: "A instrução técnica de saltos de linha e posições relativas" },
                            linesPerRecord: { type: Type.INTEGER, description: "Total de linhas que formam um bloco completo" }
                        },
                        required: ["blockRecipe", "linesPerRecord"]
                    } : {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            setActiveMapping((prev: any) => {
                if (isBlockMode) {
                    return {
                        ...prev,
                        extractionMode: 'BLOCK',
                        blockContract: `REGRA TÉCNICA: ${result.blockRecipe} | TAMANHO DO BLOCO: ${result.linesPerRecord} linhas.`,
                        dateColumnIndex: -1,
                        descriptionColumnIndex: -1,
                        amountColumnIndex: -1
                    };
                }

                const newIgnored = Array.from(new Set([
                    ...(prev.ignoredKeywords || []), 
                    ...(result.ignoredKeywords || [])
                ].map(k => k.trim().toUpperCase()))).filter(k => k.length >= 2);

                return {
                    ...prev,
                    extractionMode: 'COLUMNS',
                    dateColumnIndex: result.dateColumnIndex,
                    descriptionColumnIndex: result.descriptionColumnIndex,
                    amountColumnIndex: result.amountColumnIndex,
                    ignoredKeywords: newIgnored
                };
            });
            showToast("Padrão técnico aprendido.", "success");
        } catch (e: any) {
            console.error("[PatternTeacher] Fail:", e);
            showToast("IA não conseguiu criar a receita técnica.", "error");
        } finally {
            setIsInferringMapping(false);
            setLearnedPatternSource(null);
        }
    }, [learnedPatternSource, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

import { GoogleGenAI, Type } from "@google/genai";
import { Transaction } from '../types';
