const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        if (parsed.rows) return parsed.rows;
        return Array.isArray(parsed) ? parsed : fallback;
    } catch (e) {
        return fallback;
    }
};

export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    const ai = getAIClient();
    const prompt = `Analise a topologia deste arquivo.
    TEXTO:
    ${sampleText}`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: { 
            temperature: 0, 
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    extractionMode: { type: Type.STRING },
                    dateColumnIndex: { type: Type.INTEGER },
                    descriptionColumnIndex: { type: Type.INTEGER },
                    amountColumnIndex: { type: Type.INTEGER },
                    skipRowsStart: { type: Type.INTEGER }
                },
                required: ["extractionMode", "dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "skipRowsStart"]
            }
        }
    });
    return JSON.parse(response.text || "{}");
};

export const extractTransactionsWithModel = async (rawText: string, modelContext?: string): Promise<any> => {
    const ai = getAIClient();

    // SISTEMA DE REPLICAÇÃO RÍGIDA (V6)
    const isBlockPattern = modelContext?.includes("TAMANHO DO BLOCO");

    const finalPrompt = isBlockPattern 
    ? `VOCÊ É UM MOTOR DE AGRUPAMENTO DE LINHAS. 
       NÃO TRATE CADA LINHA COMO UM REGISTRO.

       RECEITA TÉCNICA OBRIGATÓRIA:
       ${modelContext}

       TEXTO BRUTO PARA PROCESSAR:
       ${rawText}

       INSTRUÇÃO CRÍTICA:
       1. Identifique os blocos repetitivos baseando-se no número de linhas da Receita.
       2. Consolide as informações de cada bloco em UMA ÚNICA LINHA de saída JSON.
       3. Ignore linhas que não fazem parte da estrutura do bloco (headers/footers).
       4. Respeite as posições relativas (ex: Nome está X linhas após a Data).`

    : `REPLIQUE O PADRÃO DE COLUNAS:
       ${modelContext}
       TEXTO:
       ${rawText}`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: finalPrompt,
        config: {
            temperature: 0,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    rows: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                date: { type: Type.STRING },
                                description: { type: Type.STRING },
                                amount: { type: Type.NUMBER }
                            },
                            required: ["date", "description", "amount"]
                        }
                    }
                },
                required: ["rows"]
            }
        }
    });
    return safeJsonParse(response.text);
};

