/**
 * 🎯 MOTOR DE EXTRAÇÃO DIRETA (V8 - LEITURA POR IA)
 * Se base64Data estiver presente, a IA lê o PDF original diretamente.
 */
export const extractTransactionsWithModel = async (rawText: string, modelContext?: string, base64Data?: string, mimeType: string = 'application/pdf'): Promise<any> => {
    const ai = getAIClient();

    const isBlockPattern = modelContext?.includes("RITMO") || modelContext?.includes("RECEITA");

    const instruction = isBlockPattern 
    ? `VOCÊ É UM ANALISTA DE DOCUMENTOS BANCÁRIOS. 
       LEIA O DOCUMENTO FORNECIDO E EXTRAIA AS TRANSAÇÕES SEGUINDO ESTE CONTRATO DE BLOCO:
       ${modelContext}

       INSTRUÇÕES:
       1. Identifique cada transação como um BLOCO (pode conter várias linhas físicas).
       2. Não ignore linhas intermediárias do bloco (CPF, Detalhes).
       3. Consolide cada bloco em UM registro JSON.
       4. Ignore cabeçalhos de página e rodapés.`

    : `REPLIQUE O PADRÃO DE COLUNAS:
       ${modelContext}
       TEXTO PARA PROCESSAR:
       ${rawText}`;

    const contents: any = {
        parts: []
    };

    // Se temos o arquivo bruto, enviamos para a IA "ler"
    if (base64Data && isBlockPattern) {
        contents.parts.push({
            inlineData: {
                data: base64Data,
                mimeType: mimeType
            }
        });
    }

    contents.parts.push({ text: instruction });

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: contents,
        config: {
            temperature: 0,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    rows: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                date: { type: Type.STRING },
                                description: { type: Type.STRING },
                                amount: { type: Type.NUMBER }
                            },
                            required: ["date", "description", "amount"]
                        }
                    }
                },
                required: ["rows"]
            }
        }
    });
    return safeJsonParse(response.text);
};

