            const isBlockMode = extractionMode === 'BLOCK';

            const instruction = isBlockMode 
            ? `VOCÊ É UM PROGRAMADOR DE EXTRATORES DE DOCUMENTOS. 
            Estou te enviando o PDF ORIGINAL e uma amostra de como o humano quer que eu extraia os dados dele.

            GABARITO HUMANO (Extraído do arquivo em anexo):
            - Data: "${learnedPatternSource.corrected.date}"
            - Nome/Descrição: "${learnedPatternSource.corrected.description}"
            - Valor: "${learnedPatternSource.corrected.amount}"

            SUA MISSÃO:
            1. Olhe o PDF original.
            2. Localize visualmente onde estão os dados do Gabarito.
            3. Crie uma "RECEITA DE FATIAMENTO" descrevendo o bloco. 
               Ex: "O bloco começa com uma data, o nome está 2 linhas abaixo, o valor está na mesma linha da data."
            4. Identifique o número de linhas físicas que compõem 1 registro completo.`

            : `VOCÊ É UM EXTRATOR DE PADRÕES ESTRUTURAIS LATERAIS.
            Mapeie os índices de colunas (0 a N) baseando-se na correção:
            BRUTO: "${learnedPatternSource.originalRaw.join(' ; ')}"
            GABARITO: Data: "${learnedPatternSource.corrected.date}", Nome: "${learnedPatternSource.corrected.description}", Valor: "${learnedPatternSource.corrected.amount}"`;

            const contents: any = { parts: [] };

            if (isBlockMode && rawBase64) {
                contents.parts.push({
                    inlineData: {
                        data: rawBase64,
                        mimeType: 'application/pdf'
                    }
                });
            }

            contents.parts.push({ text: instruction });

            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: contents,
                config: { 
                    temperature: 0,
                    responseMimeType: "application/json",
                    responseSchema: isBlockMode ? {
                        type: Type.OBJECT,
                        properties: {
                            blockRecipe: { type: Type.STRING },
                            linesPerRecord: { type: Type.INTEGER }
                        },
                        required: ["blockRecipe", "linesPerRecord"]
                    } : {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            setActiveMapping((prev: any) => {
                if (isBlockMode) {
                    return {
                        ...prev,
                        extractionMode: 'BLOCK',
                        blockContract: `RECEITA VISUAL: ${result.blockRecipe} | RITMO: ${result.linesPerRecord} linhas.`,
                        dateColumnIndex: -1,
                        descriptionColumnIndex: -1,
                        amountColumnIndex: -1
                    };
                }

                const newIgnored = Array.from(new Set([
                    ...(prev.ignoredKeywords || []), 
                    ...(result.ignoredKeywords || [])
                ].map(k => k.trim().toUpperCase()))).filter(k => k.length >= 2);

                return {
                    ...prev,
                    extractionMode: 'COLUMNS',
                    dateColumnIndex: result.dateColumnIndex,
                    descriptionColumnIndex: result.descriptionColumnIndex,
                    amountColumnIndex: result.amountColumnIndex,
                    ignoredKeywords: newIgnored
                };
            });
            showToast("Padrão de bloco visual aprendido.", "success");
        } catch (e: any) {
            console.error("[PatternTeacher] Fail:", e);
            showToast("Erro ao ler o documento visualmente.", "error");
        } finally {
            setIsInferringMapping(false);
            setLearnedPatternSource(null);
        }
    }, [learnedPatternSource, rawBase64, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { TypeResolver } from '../processors/TypeResolver';
import { NameResolver } from '../processors/NameResolver';
import { extractTransactionsWithModel } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V45 - LEITURA DIRETA POR IA)
 */
export const ContractExecutor = {
    async apply(model: FileModel, adaptedInput: any, globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        const rawBase64 = adaptedInput?.__base64; // NOVO: Captura o arquivo bruto se existir

        if (!rawText.trim() && !rawBase64) return [];

        const { mapping, parsingRules } = model;

        // 🧱 MODO BLOCO (LEITURA VISUAL DIRETA)
        if (mapping.extractionMode === 'BLOCK') {
            console.log(`[ContractExecutor] 👁️ Enviando Documento para Leitura IA: ${model.name}`);

            const trainingContext = mapping.blockContract || 'Extração por blocos de texto.';

            // No modo bloco com visão, enviamos o documento inteiro (ou chunks maiores)
            try {
                const aiResult = await extractTransactionsWithModel(rawText, trainingContext, rawBase64);
                return (aiResult || []).map((tx: any, idx: number) => ({
                    id: `exec-v45-block-${model.id}-${idx}-${Date.now()}`,
                    date: tx.date,
                    description: tx.description,
                    rawDescription: tx.description,
                    amount: tx.amount,
                    originalAmount: String(tx.amount),
                    cleanedDescription: tx.description,
                    contributionType: 'AUTO',
                    paymentMethod: 'OUTROS',
                    bank_id: model.id
                }));
            } catch (e) { 
                console.error("[ContractExecutor] Erro na leitura IA:", e);
                return []; 
            }
        }

        // 🚀 MODO COLUNAS (DETERMINÍSTICO)
        const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);
        const results: Transaction[] = [];
        const currentYear = new Date().getFullYear();
        const modelKeywords = parsingRules?.ignoredKeywords || (mapping as any).ignoredKeywords || [];

        lines.forEach((line, idx) => {
            if (idx < (mapping.skipRowsStart || 0)) return;

            const cells = line.split(';'); 
            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";

            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, currentYear);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            if (isoDate && !isNaN(numAmount)) {
                const cleanedName = NameResolver.clean(rawDesc, modelKeywords, globalKeywords);

                results.push({
                    id: `exec-v45-col-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: cleanedName,
                    rawDescription: rawDesc,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: cleanedName,
                    contributionType: TypeResolver.resolveFromDescription(rawDesc),
                    paymentMethod: mapping.paymentMethodColumnIndex !== undefined && cells[mapping.paymentMethodColumnIndex] 
                        ? cells[mapping.paymentMethodColumnIndex] 
                        : TypeResolver.resolveFromDescription(rawDesc),
                    bank_id: model.id
                });
            }
        });

        return results;
    }
};

import { useState, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { generateFingerprint } from '../services/processingService';
import { FileModel } from '../types';
import { useUI } from '../contexts/UIContext';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';

interface UseFileProcessingProps {
    activeFile: { content: string; fileName: string; rawFile?: File; base64?: string } | null;
    initialModel?: FileModel;
    isPdf: boolean;
}

export const useFileProcessing = ({ activeFile, initialModel, isPdf }: UseFileProcessingProps) => {
    const [gridData, setGridData] = useState<string[][]>([]);
    const [isGridLoading, setIsGridLoading] = useState(false);
    const [isAiProcessing, setIsAiProcessing] = useState(false);
    const [activeMapping, setActiveMapping] = useState<any>(null);
    const [detectedFingerprint, setDetectedFingerprint] = useState<any>(null);
    const [rawBase64, setRawBase64] = useState<string | undefined>(undefined);

    const { showToast } = useUI();

    const processingRef = useRef<string | null>(null);

    useEffect(() => {
        if (!activeFile) {
            setGridData([]);
            setActiveMapping(null);
            setDetectedFingerprint(null);
            setRawBase64(undefined);
            processingRef.current = null;
            return;
        }

        setRawBase64(activeFile.base64);

        const fileKey = `${activeFile.fileName}-${activeFile.content?.length || 0}`;
        if (processingRef.current === fileKey) return;
        processingRef.current = fileKey;

        const loadContent = async () => {
            setIsGridLoading(true);
            setIsAiProcessing(false);
            let loadedRows: string[][] = [];

            try {
                if (activeFile.rawFile && (activeFile.fileName.toLowerCase().endsWith('xls') || activeFile.fileName.toLowerCase().endsWith('xlsx'))) {
                    const buffer = await activeFile.rawFile.arrayBuffer();
                    const wb = XLSX.read(new Uint8Array(buffer), { type: 'array' });
                    const sheet = wb.Sheets[wb.SheetNames[0]];
                    const rawData = XLSX.utils.sheet_to_json<any[]>(sheet, { header: 1, defval: '' });

                    loadedRows = rawData
                        .filter(row => row.join('').trim().length > 0)
                        .map(row => row.map(cell => String(cell || '').trim()));
                } 
                else {
                    const content = activeFile.content || "";
                    if (content.trim()) {
                        const normalized = IngestionOrchestrator.normalizeRawContent(content);
                        loadedRows = normalized.split('\n').map(line => line.split(';'));
                    }
                }

                if (loadedRows.length > 0) {
                    setGridData(loadedRows);
                    const sampleContentForFp = loadedRows.slice(0, 30).map(r => r.join(';')).join('\n');
                    const fp = generateFingerprint(sampleContentForFp);
                    setDetectedFingerprint(fp);

                    if (initialModel?.mapping) {
                        setActiveMapping(initialModel.mapping);
                    } else {
                        setActiveMapping({
                            extractionMode: 'COLUMNS',
                            dateColumnIndex: -1,
                            descriptionColumnIndex: -1,
                            amountColumnIndex: -1,
                            skipRowsStart: 0
                        });
                    }
                }
            } catch (err) {
                console.error("Erro no laboratório:", err);
                showToast("Erro ao ler estrutura do arquivo.", "error");
            } finally {
                setIsGridLoading(false);
            }
        };

        loadContent();
    }, [activeFile, isPdf, initialModel, showToast]);

    return {
        gridData,
        setGridData,
        isGridLoading,
        isAiProcessing,
        activeMapping,
        setActiveMapping,
        detectedFingerprint,
        rawBase64
    };
};

