                setIsLoading(false);
            }
        };

        loadPDF();
    }, [file]);

    return (
        <div className="absolute inset-0 bg-slate-200 dark:bg-slate-950 flex flex-col">
            {/* Header de Status */}
            {!isLoading && !error && pages.length > 0 && (
