export const FilePreprocessorModal: React.FC<{ 
    onClose: () => void; 
    initialFile?: any;
    initialModel?: FileModel; 
    onSuccess?: (model: FileModel, data: Transaction[]) => void;
    mode?: 'create' | 'test' | 'refine'; 
}> = ({ onClose, initialFile, initialModel, onSuccess, mode = 'create' }) => {
    const { showToast } = useUI();
    const { user } = useAuth(); 
    const context = useContext(AppContext);

    const effectiveIgnoreKeywords = context?.effectiveIgnoreKeywords || [];
    const contributionKeywords = context?.contributionKeywords || [];
    const fetchModels = context?.fetchModels;

    const [uploadedFile, setUploadedFile] = useState<{ content: string, fileName: string, rawFile?: File, base64?: string } | null>(null);

    useEffect(() => {
        if (mode === 'refine' && initialModel && !uploadedFile && !initialFile) {
            setUploadedFile({
                content: initialModel.snippet || "",
                fileName: initialModel.name,
                rawFile: undefined
            });
        }
    }, [mode, initialModel, uploadedFile, initialFile]);

    const activeFile = initialFile || uploadedFile || null;
    const isPdf = useMemo(() => /\.pdf$/i.test(activeFile?.fileName || ''), [activeFile]);

    const cleaningKeywords = useMemo(() => [
        ...(effectiveIgnoreKeywords || []), 
        ...(contributionKeywords || [])
    ], [effectiveIgnoreKeywords, contributionKeywords]);

    const { 
        gridData, setGridData, isGridLoading,
        activeMapping, setActiveMapping, detectedFingerprint, rawBase64
    } = useFileProcessing({ activeFile, initialModel, isPdf });

    const {
        processedTransactions, isSimulating, editingRowIndex, editingRowData, 
        setEditingRowData, startEdit, saveRow, cancelEdit, runSimulation
    } = useSimulation({ 
        gridData, 
        activeMapping, 
        cleaningKeywords, 
        rawBase64: activeFile?.base64 || rawBase64 
    });

    const {
        isInferringMapping, learnedPatternSource, setLearnedPatternSource, handleApplyCorrectionPattern
    } = useAIPatternTeacher({ 
        gridData, 
        setGridData, 
        setActiveMapping, 
        showToast,
        fullFileText: activeFile?.content,
        rawBase64: activeFile?.base64 || rawBase64
    });

    const [isSavingModel, setIsSavingModel] = useState(false);
    const [showNameModal, setShowNameModal] = useState(false);
    const [pendingAction, setPendingAction] = useState<'draft' | 'approved'>('draft');
    const [modelName, setModelName] = useState(initialModel?.name || '');

    const handlePersistModel = useCallback(async (approvalStatus: 'draft' | 'approved', finalName: string) => {
        if (!activeMapping || !detectedFingerprint || !user) return;

        setIsSavingModel(true);
        try {
            const finalSnippet = gridData.map(row => row.join(';')).join('\n');
            const learnedKeywords = activeMapping.ignoredKeywords || [];

            const modelData: any = { 
                name: finalName, 
                user_id: user.id, 
                version: initialModel ? initialModel.version + 1 : 1, 
                lineage_id: initialModel ? initialModel.lineage_id : `mod-${Date.now()}`, 
                is_active: true, 
                fingerprint: { ...detectedFingerprint }, 
                mapping: { ...activeMapping }, 
                parsingRules: { ignoredKeywords: learnedKeywords, rowFilters: [] }, 
                snippet: finalSnippet, 
                status: approvalStatus 
            };

            const saved = await modelService.saveModel(modelData);
            if (saved) {
                showToast("Modelo salvo com sucesso!", "success");
                if (fetchModels) await fetchModels();
                if (onSuccess) onSuccess(saved as FileModel, []);
                onClose();
            }
        } catch (e: any) { 
            showToast("Erro ao salvar padrão.", "error"); 
        } finally { setIsSavingModel(false); }
    }, [activeMapping, detectedFingerprint, user, gridData, initialModel, onSuccess, onClose, showToast, fetchModels]);

    return createPortal(
        <div className="fixed inset-0 z-[9999] bg-[#050B14]/90 backdrop-blur-md flex items-center justify-center p-2 sm:p-4 animate-fade-in overflow-hidden">
            <div className="bg-white dark:bg-[#0F172A] w-full max-w-[1600px] h-full max-h-[95dvh] rounded-[2.5rem] shadow-2xl border border-white/10 flex flex-col overflow-hidden animate-scale-in relative">

                <PreprocessorHeader 
                    fileName={activeFile?.fileName || 'Laboratório de IA'} 
                    canApprove={processedTransactions.length > 0} 
                    onApprove={() => { setPendingAction('approved'); setShowNameModal(true); }}
                    onClose={onClose}
                />

                <div className="px-6 py-3 bg-slate-50 dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between shrink-0">
                    <MappingControls mapping={activeMapping} setMapping={setActiveMapping} columnCount={gridData[0]?.length || 0} onSimulate={runSimulation} gridData={gridData} />
                </div>

                <div className="flex-1 flex flex-col lg:flex-row overflow-hidden min-h-0">
                    <section className="flex-1 flex flex-col border-r border-slate-200 dark:border-slate-800 bg-slate-100 dark:bg-[#0B1120] relative">
                        {isGridLoading ? (
                            <div className="absolute inset-0 flex flex-col items-center justify-center"><div className="animate-spin rounded-full h-8 w-8 border-4 border-indigo-500 border-t-transparent mb-3"></div><p className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Lendo arquivo...</p></div>
                        ) : !activeFile ? (
                            <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center">
                                <TableCellsIcon className="w-16 h-16 text-indigo-500 mb-4 opacity-20" />
                                <FileUploader id="pre-up" title="Selecionar Documento" onFileUpload={(c,f,r,b) => setUploadedFile({content:c, fileName:f, rawFile:r, base64:b})} isUploaded={false} uploadedFileName={null} useLocalLoadingOnly={true} />
                            </div>
                        ) : (isPdf && activeFile.rawFile) ? <PDFRenderer file={activeFile.rawFile} /> : <SpreadsheetRenderer data={gridData} detectedMapping={activeMapping} />}
                    </section>

                    <section className="flex-1 flex flex-col min-h-0 bg-white dark:bg-[#0F172A] relative">
                        <TeachingBanner isVisible={!!learnedPatternSource} isProcessing={isInferringMapping} onApply={() => handleApplyCorrectionPattern('BLOCK')} />
                        <div className="flex-1 overflow-auto custom-scrollbar">
                            <SimulatedResultsTable 
                                transactions={processedTransactions} 
                                activeMapping={!!activeMapping} 
                                isTestMode={mode === 'test'} 
                                isSimulating={isSimulating}
                                editingRowIndex={editingRowIndex} 
                                editingRowData={editingRowData} 
                                onStartEdit={startEdit} 
                                onSaveRow={() => saveRow((raw, corr) => setLearnedPatternSource({ originalRaw: raw, corrected: corr }))} 
                                onCancelEdit={cancelEdit} 
                                onUpdateEditingData={setEditingRowData} 
                            />
                        </div>
                    </section>
                </div>

                {showNameModal && (
                    <div className="fixed inset-0 z-[10000] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in">
                        <div className="bg-white dark:bg-slate-900 p-6 rounded-[2rem] shadow-2xl w-full max-w-sm border border-white/10 animate-scale-in text-center">
                            <h3 className="text-xl font-black text-slate-800 dark:text-white mb-4">Nomear Padrão</h3>
                            <input type="text" autoFocus value={modelName} onChange={e => setModelName(e.target.value)} className="w-full p-4 rounded-2xl border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-800 text-slate-800 dark:text-white mb-6 outline-none font-bold shadow-inner" placeholder="Ex: Extrato Itaú PJ" />
                            <div className="flex gap-3">
                                <button onClick={() => setShowNameModal(false)} className="flex-1 py-3 bg-slate-100 dark:bg-slate-800 rounded-2xl font-bold uppercase text-[10px] text-slate-600">Voltar</button>
                                <button onClick={() => { setShowNameModal(false); handlePersistModel(pendingAction, modelName); }} disabled={isSavingModel || !modelName.trim()} className="flex-1 py-3 bg-indigo-600 text-white rounded-2xl font-bold uppercase text-[10px] shadow-lg active:scale-95 transition-all">Salvar</button>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>,
        document.body
    );
};

import { GoogleGenAI, Type } from "@google/genai";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        if (parsed.rows) return parsed.rows;
        return Array.isArray(parsed) ? parsed : fallback;
    } catch (e) {
        return fallback;
    }
};

/**
 * 🛠️ DUMP ESTRUTURAL (SEM ADIVINHAÇÃO)
 * Apenas lista o que vê no documento para que o humano ensine o padrão.
 */
export const getRawStructuralDump = async (base64Data: string): Promise<any[]> => {
    const ai = getAIClient();

    const instruction = `VOCÊ É UM TRANSCRITOR BURRO E FIEL. 
    Sua única tarefa é listar todos os fragmentos de texto, linhas ou blocos que encontrar no documento.

    REGRAS:
    1. NÃO TENTE IDENTIFICAR O QUE É DATA, VALOR OU NOME.
    2. NÃO CRIE COLUNAS.
    3. Retorne cada linha ou bloco lógico de texto como uma string simples num array JSON chamado "rawLines".`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: {
            parts: [
                { inlineData: { data: base64Data, mimeType: 'application/pdf' } },
                { text: instruction }
            ]
        },
        config: {
            temperature: 0,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    rawLines: {
                        type: Type.ARRAY,
                        items: { type: Type.STRING }
                    }
                },
                required: ["rawLines"]
            }
        }
    });

    const result = JSON.parse(response.text || '{"rawLines": []}');
    return result.rawLines || [];
};

export const inferMappingFromSample = async (sampleText: string): Promise<any> => {
    const ai = getAIClient();
    const prompt = `Analise a estrutura física deste documento financeiro. Escolha 'BLOCK' para documentos visuais.
    TEXTO: ${sampleText}`;

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: { 
            temperature: 0, 
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    extractionMode: { type: Type.STRING },
                    dateColumnIndex: { type: Type.INTEGER },
                    descriptionColumnIndex: { type: Type.INTEGER },
                    amountColumnIndex: { type: Type.INTEGER },
                    skipRowsStart: { type: Type.INTEGER }
                },
                required: ["extractionMode", "dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "skipRowsStart"]
            }
        }
    });
    return JSON.parse(response.text || "{}");
};

/**
 * 🎯 MOTOR DE EXTRAÇÃO ENSINADO
 * Só é chamado quando já existe um modelo ou contrato definido.
 */
export const extractTransactionsWithModel = async (rawText: string, modelContext?: string, base64Data?: string): Promise<any> => {
    const ai = getAIClient();

    const instruction = `VOCÊ É UM EXTRATOR RÍGIDO.

       USE ESTA RECEITA/CONTRATO APRENDIDO PARA EXTRAIR OS DADOS:
       ${modelContext}

       REGRAS:
       1. SIGA EXATAMENTE O PADRÃO DE BLOCO OU COLUNA INFORMADO.
       2. FORMATO: JSON com chave "rows" contendo {date, description, amount}.`;

    const contents: any = { parts: [] };
    if (base64Data) {
        contents.parts.push({ inlineData: { data: base64Data, mimeType: 'application/pdf' } });
    }
    contents.parts.push({ text: instruction });

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: contents,
        config: {
            temperature: 0,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    rows: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                date: { type: Type.STRING },
                                description: { type: Type.STRING },
                                amount: { type: Type.NUMBER }
                            },
                            required: ["date", "description", "amount"]
                        }
                    }
                },
                required: ["rows"]
            }
        }
    });
    return safeJsonParse(response.text);
};

import { useState, useCallback, useEffect, useRef } from 'react';
import { Transaction } from '../types';
import { DateResolver } from '../core/processors/DateResolver';
import { AmountResolver } from '../core/processors/AmountResolver';
import { TypeResolver } from '../core/processors/TypeResolver';
import { NameResolver } from '../core/processors/NameResolver';
import { extractTransactionsWithModel, getRawStructuralDump } from '../services/geminiService';

interface SafeTransaction extends Transaction {
    sourceIndex?: number;
    isValid?: boolean;
    status?: 'valid' | 'error' | 'edited' | 'ignored' | 'pending';
    sourceRawSnippet?: string[];
}

interface UseSimulationProps {
    gridData: string[][];
    activeMapping: any;
    cleaningKeywords: string[];
    rawBase64?: string;
}

export const useSimulation = ({ gridData, activeMapping, cleaningKeywords, rawBase64 }: UseSimulationProps) => {
    const [processedTransactions, setProcessedTransactions] = useState<SafeTransaction[]>([]);
    const [editingRowIndex, setEditingRowIndex] = useState<number | null>(null);
    const [editingRowData, setEditingRowData] = useState<SafeTransaction | null>(null);
    const [isSimulating, setIsSimulating] = useState(false);

    const lastDataRef = useRef<string>('');
    const lastMappingRef = useRef<string>('');
    const initialReadDone = useRef<string | null>(null);

    const runSimulation = useCallback(async () => {
        if (!gridData || gridData.length === 0) {
            setProcessedTransactions([]);
            return;
        }

        const mapping = activeMapping || { extractionMode: 'COLUMNS' };
        const isBlockMode = mapping.extractionMode === 'BLOCK';

        // 🧱 MODO BLOCO (TREINAMENTO IA)
        if (isBlockMode) {
            const isVisualDoc = gridData[0]?.[0] === '[DOCUMENTO_VISUAL]' || gridData[0]?.[0] === '[DOCUMENTO_PDF_VISUAL]';

            // Se o usuário ainda não ensinou nada (não há blockContract)
            if (isVisualDoc && !mapping.blockContract) {
                if (rawBase64 && initialReadDone.current !== rawBase64.substring(0, 100)) {
                    setIsSimulating(true);
                    try {
                        console.log("[Simulation] Realizando Dump Bruto de texto...");
                        const rawLines = await getRawStructuralDump(rawBase64);

                        const mapped = rawLines.map((line: string, i: number) => ({
                            id: `raw-dump-${i}-${Date.now()}`,
                            date: "---",
                            description: line, 
                            rawDescription: line,
                            amount: 0,
                            originalAmount: "0.00",
                            isValid: false,
                            status: 'pending' as const,
                            sourceIndex: i,
                            sourceRawSnippet: [line]
                        }));

                        setProcessedTransactions(mapped);
                        initialReadDone.current = rawBase64.substring(0, 100);
                    } catch (e) {
                        console.error("[Simulation] Falha no dump bruto:", e);
                    } finally {
                        setIsSimulating(false);
                    }
                }
                return;
            }

            // Se já foi ensinado (tem blockContract), a IA processa conforme o modelo
            if (isVisualDoc && mapping.blockContract) {
                setIsSimulating(true);
                try {
                    console.log("[Simulation] Extraindo dados com base no modelo ensinado...");
                    const aiResults = await extractTransactionsWithModel("", mapping.blockContract, rawBase64);

                    const mapped = (aiResults || []).map((tx: any, i: number) => ({
                        id: `ai-extracted-${i}-${Date.now()}`,
                        date: tx.date || "---",
                        description: tx.description || "---",
                        rawDescription: tx.description || "",
                        amount: tx.amount || 0,
                        originalAmount: String(tx.amount || "0"),
                        isValid: true,
                        status: 'valid' as const,
                        sourceIndex: 0
                    }));

                    setProcessedTransactions(mapped);
                } catch (e) {
                    console.error("[Simulation] Falha na extração ensinada:", e);
                } finally {
                    setIsSimulating(false);
                }
                return;
            }
        }

        // 🚀 MODO COLUNAS (DETERMINÍSTICO)
        const isManualMappingComplete = mapping.dateColumnIndex >= 0 && mapping.amountColumnIndex >= 0;

        if (!isManualMappingComplete) {
            const initialPreview = gridData.slice(0, 100).map((row, i) => ({
                id: `raw-${i}-${Date.now()}`,
                date: "---",
                description: row.join(' ').substring(0, 150),
                rawDescription: row.join(';'),
                amount: 0,
                originalAmount: "0.00",
                isValid: false,
                status: 'pending' as const,
                sourceIndex: i,
                sourceRawSnippet: row
            }));
            setProcessedTransactions(initialPreview);
            return;
        }

        setIsSimulating(true);
        const { dateColumnIndex, descriptionColumnIndex, amountColumnIndex, paymentMethodColumnIndex, skipRowsStart, ignoredKeywords } = mapping;
        const newTransactions: SafeTransaction[] = [];
        const yearAnchor = DateResolver.discoverAnchorYear(gridData);

        gridData.forEach((cols, index) => {
            const isSkipped = index < (skipRowsStart || 0);
            const rawDate = dateColumnIndex >= 0 ? (cols[dateColumnIndex] || '') : '';
            const rawDesc = descriptionColumnIndex >= 0 ? (cols[descriptionColumnIndex] || '') : '';
            const rawAmount = amountColumnIndex >= 0 ? (cols[amountColumnIndex] || '') : '';

            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, yearAnchor);
            const amountStr = AmountResolver.clean(rawAmount);
            const amountValue = parseFloat(amountStr);
            const cleanedName = NameResolver.clean(rawDesc, ignoredKeywords || [], cleaningKeywords);

            newTransactions.push({ 
                id: `sim-${index}-${Date.now()}`,
                date: isoDate || rawDate || "---", 
                description: cleanedName, 
                rawDescription: rawDesc || "---", 
                paymentMethod: (paymentMethodColumnIndex !== undefined && paymentMethodColumnIndex >= 0 && cols[paymentMethodColumnIndex]) ? cols[paymentMethodColumnIndex] : TypeResolver.resolveFromDescription(rawDesc),
                amount: isNaN(amountValue) ? 0 : amountValue, 
                originalAmount: rawAmount, 
                cleanedDescription: cleanedName, 
                contributionType: 'AUTO', 
                sourceIndex: index, 
                sourceRawSnippet: cols,
                isValid: !!isoDate && !isNaN(amountValue), 
                status: isSkipped ? 'ignored' : 'valid'
            });
        });
        setProcessedTransactions(newTransactions);
        setIsSimulating(false);
    }, [gridData, activeMapping, cleaningKeywords, rawBase64]);

    useEffect(() => {
        const dataHash = gridData.length > 0 ? `${gridData.length}-${gridData[0].join('|').substring(0, 50)}` : 'empty';
        const mappingKey = JSON.stringify(activeMapping);
        if (dataHash !== lastDataRef.current || mappingKey !== lastMappingRef.current) {
            lastDataRef.current = dataHash;
            lastMappingRef.current = mappingKey;
            runSimulation();
        }
    }, [gridData, activeMapping, runSimulation]);

    return {
        processedTransactions, isSimulating, runSimulation, editingRowIndex, editingRowData, setEditingRowData,
        startEdit: (tx: any, idx: number) => { setEditingRowIndex(idx); setEditingRowData({ ...tx }); },
        saveRow: (onLearned?: (raw: string[], corrected: any) => void) => {
            if (editingRowIndex !== null && editingRowData) {
                const updatedTx = { ...editingRowData, status: 'edited' as const, isValid: true };
                if (onLearned) onLearned(updatedTx.sourceRawSnippet || [], updatedTx);
                setProcessedTransactions(prev => { const n = [...prev]; n[editingRowIndex] = updatedTx; return n; });
                setEditingRowIndex(null);
            }
        },
        cancelEdit: () => setEditingRowIndex(null)
    };
};

import { Transaction, FileModel } from '../../types';
import { DateResolver } from '../processors/DateResolver';
import { AmountResolver } from '../processors/AmountResolver';
import { TypeResolver } from '../processors/TypeResolver';
import { NameResolver } from '../processors/NameResolver';
import { extractTransactionsWithModel } from '../../services/geminiService';

/**
 * 📜 CONTRACT EXECUTOR (V46 - FIDELIDADE TOTAL AO MODELO)
 * Este componente aplica as regras de um modelo salvo sem aplicar limpezas globais.
 */
export const ContractExecutor = {
    async apply(model: FileModel, adaptedInput: any, globalKeywords: string[] = []): Promise<Transaction[]> {
        if (!model || !model.mapping) return [];

        const rawText = adaptedInput?.__rawText || (typeof adaptedInput === 'string' ? adaptedInput : "");
        const rawBase64 = adaptedInput?.__base64; 

        if (!rawText.trim() && !rawBase64) return [];

        const { mapping } = model;

        // 🧱 MODO BLOCO (LEITURA VISUAL POR IA - CONFORME MODELO)
        if (mapping.extractionMode === 'BLOCK') {
            const trainingContext = mapping.blockContract || 'Extração fiel conforme modelo.';

            try {
                // O Gemini recebe o contrato aprendido e o arquivo original
                const aiResult = await extractTransactionsWithModel(rawText, trainingContext, rawBase64);

                return (aiResult || []).map((tx: any, idx: number) => ({
                    id: `exec-v46-block-${model.id}-${idx}-${Date.now()}`,
                    date: tx.date,
                    description: tx.description, // Conteúdo pronto da IA conforme o contrato
                    rawDescription: tx.description,
                    amount: tx.amount,
                    originalAmount: String(tx.amount),
                    cleanedDescription: tx.description,
                    contributionType: 'AUTO',
                    paymentMethod: 'OUTROS',
                    bank_id: model.id
                }));
            } catch (e) { 
                console.error("[ContractExecutor] Erro na leitura IA por contrato:", e);
                return []; 
            }
        }

        // 🚀 MODO COLUNAS (MAPEAMENTO DETERMINÍSTICO DIRETO)
        const lines = rawText.split(/\r?\n/).filter(l => l.trim().length > 0);
        const results: Transaction[] = [];
        const currentYear = new Date().getFullYear();

        lines.forEach((line, idx) => {
            // Pula headers conforme definido no modelo
            if (idx < (mapping.skipRowsStart || 0)) return;

            const cells = line.split(';'); 
            const rawDate = cells[mapping.dateColumnIndex] || "";
            const rawDesc = cells[mapping.descriptionColumnIndex] || "";
            const rawAmount = cells[mapping.amountColumnIndex] || "";

            // Se a linha essencial estiver vazia, ignora
            if (!rawDate && !rawDesc && !rawAmount) return;

            const isoDate = DateResolver.resolveToISO(rawDate, currentYear);
            const stdAmount = AmountResolver.clean(rawAmount);
            const numAmount = parseFloat(stdAmount);

            // Se conseguirmos pelo menos uma data válida e um valor, capturamos o dado
            if (isoDate && !isNaN(numAmount)) {
                // ⚠️ RIGOR: Não aplicamos NameResolver.clean aqui. 
                // Pegamos o conteúdo da coluna de descrição exatamente como ele é.
                const finalDescription = rawDesc.trim();

                results.push({
                    id: `exec-v46-col-${model.id}-${idx}-${Date.now()}`,
                    date: isoDate,
                    description: finalDescription,
                    rawDescription: rawDesc,
                    amount: numAmount,
                    originalAmount: rawAmount,
                    cleanedDescription: finalDescription,
                    contributionType: TypeResolver.resolveFromDescription(rawDesc),
                    paymentMethod: mapping.paymentMethodColumnIndex !== undefined && cells[mapping.paymentMethodColumnIndex] 
                        ? cells[mapping.paymentMethodColumnIndex] 
                        : TypeResolver.resolveFromDescription(rawDesc),
                    bank_id: model.id
                });
            }
        });

        return results;
    }
};

import { GoogleGenAI, Type } from "@google/genai";

const getAIClient = () => {
    if (!process.env.API_KEY) throw new Error("Chave de API do Gemini não configurada.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

const safeJsonParse = (input: any, fallback: any = []) => {
    if (!input) return fallback;
    let sanitized = String(input).trim();
    sanitized = sanitized.replace(/^```json\s*/g, '').replace(/\s*```$/g, '');

    try {
        const parsed = JSON.parse(sanitized);
        if (parsed.rows) return parsed.rows;
        return Array.isArray(parsed) ? parsed : fallback;
    } catch (e) {
        return fallback;
    }
};

/**
 * 🛠️ DUMP ESTRUTURAL (MODO LABORATÓRIO - INÍCIO)
 * Apenas lista o que vê no documento para que o humano ensine o padrão.
 */
export const getRawStructuralDump = async (base64Data: string): Promise<any[]> => {
