/**
 * 🎯 MOTOR DE EXTRAÇÃO RÍGIDO (APLICAÇÃO DE MODELO)
 * Extrai os dados seguindo a receita aprendida, sem alterar os nomes.
 */
export const extractTransactionsWithModel = async (rawText: string, modelContext?: string, base64Data?: string): Promise<any> => {
    const ai = getAIClient();

    const instruction = `VOCÊ É UM EXTRATOR DE DADOS RÍGIDO E LITERAL.

       Sua missão é extrair TODAS as transações válidas do documento seguindo esta RECEITA/CONTRATO:
       ${modelContext}

       REGRAS CRÍTICAS:
       1. NÃO RE-ESCREVA AS DESCRIÇÕES. Use o texto exatamente como aparece no documento.
       2. NÃO TENTE SER INTELIGENTE. Apenas fatiar os dados conforme o padrão informado.
       3. EXTRAIA TUDO. Se houver 100 transações no padrão, extraia as 100.
       4. FORMATO: JSON com chave "rows" contendo {date, description, amount}.`;

    const contents: any = { parts: [] };
    if (base64Data) {
        contents.parts.push({ inlineData: { data: base64Data, mimeType: 'application/pdf' } });
    }
    contents.parts.push({ text: instruction });

    const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: contents,
        config: {
            temperature: 0,
            responseMimeType: "application/json",
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    rows: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                date: { type: Type.STRING },
                                description: { type: Type.STRING },
                                amount: { type: Type.NUMBER }
                            },
                            required: ["date", "description", "amount"]
                        }
                    }
                },
                required: ["rows"]
            }
        }
    });
    return safeJsonParse(response.text);
};

import { Transaction, FileModel } from '../types';
import { StrategyEngine, StrategyResult } from '../core/strategies';
import { Fingerprinter } from '../core/processors/Fingerprinter';
import { IngestionOrchestrator } from '../core/engine/IngestionOrchestrator';

export * from './utils/parsingUtils';
export * from './logic/matchingLogic';
export * from './logic/filteringLogic';

export const generateFingerprint = Fingerprinter.generate;

/**
 * 🛠️ ADAPTER ESTRUTURAL (V3 - PRESERVAÇÃO DE BINÁRIO)
 */
function normalizeIngestionInput(input: any) {
    if (Array.isArray(input)) return input;
    if (typeof input === 'string') {
        return {
            __rawText: input,
            __source: 'file'
        };
    }
    // Se já for um objeto (como o vindo do IngestionOrchestrator), preservamos campos especiais como __base64
    return input;
}

export const findMatchingModel = (content: string, models: FileModel[]): { model: FileModel, score: number } | null => {
    if (!models || models.length === 0) return null;
    const fileFp = Fingerprinter.generate(content);
    if (!fileFp) return null;

    // RIGOR ABSOLUTO: O match deve ser baseado no HeaderHash (DNA estrutural).
    const bestMatch = models.find(m => m.is_active && m.fingerprint.headerHash === fileFp.headerHash);

    return bestMatch ? { model: bestMatch, score: 100 } : null;
};

/**
 * PROCESSADOR DE PIPELINE (V15 - FLUXO DE VISÃO INTEGRAL)
 */
export const processFileContent = async (
    content: string, 
    fileName: string, 
    models: FileModel[] = [], 
    globalKeywords: string[] = [],
    base64?: string // Adicionado parâmetro opcional para Base64
): Promise<StrategyResult & { appliedModel?: any }> => {

    const normalizedContent = IngestionOrchestrator.normalizeRawContent(content);
    const matchResult = findMatchingModel(normalizedContent, models);
    const targetModel = matchResult?.model;

    // Criamos o input adaptado preservando o Base64 se ele existir
    const adaptedInput = {
        __rawText: normalizedContent,
        __base64: base64, // Crucial para o ContractExecutor em modo BLOCK
        __source: 'file'
    };

    // O StrategyEngine agora decide se processa ou se pede modelo.
    const result = await StrategyEngine.process(
        fileName, 
        adaptedInput, 
        models, 
        targetModel ? [] : globalKeywords,
        targetModel
    );

    if (result.status === 'MODEL_REQUIRED') {
        return result;
    }

    const transactions = Array.isArray(result?.transactions) ? result.transactions : [];

    return {
        ...result,
        transactions,
        appliedModel: targetModel ? { id: targetModel.id, name: targetModel.name, confidenceScore: 100 } : undefined
    };
};

export const parseContributors = (content: string, ignoreKeywords: string[] = [], typeKeywords: string[] = []): any[] => {
    const lines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    if (lines.length < 2) return [];
    const delimiter = Fingerprinter.detectDelimiter(lines[0]);
    const rows = lines.map(l => l.split(delimiter));

    const contributors = rows.slice(1).map(row => ({
        name: row[0] || 'Desconhecido',
        amount: parseFloat(String(row[1] || '0').replace(/[R$\s]/g, '').replace(',', '.')) || 0,
        date: row[2] || ''
    })).filter(c => c.name !== 'Desconhecido');

    return contributors;
};

import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
    rawBase64?: string; 
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast,
    rawBase64
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async (extractionMode: 'COLUMNS' | 'BLOCK' = 'COLUMNS') => {
        if (!learnedPatternSource) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            const isBlockMode = extractionMode === 'BLOCK';

            const instruction = isBlockMode 
            ? `VOCÊ É UM ANALISTA DE ESTRUTURAS FINANCEIRAS. 
            Estou te enviando um documento PDF e uma amostra de uma linha que corrigi manualmente.

            AMOSTRA REAL (O que eu quero extrair):
            - Data: "${learnedPatternSource.corrected.date}"
            - Descrição: "${learnedPatternSource.corrected.description}"
            - Valor: "${learnedPatternSource.corrected.amount}"

            SUA MISSÃO:
            1. Analise o layout do PDF.
            2. Localize onde os dados acima aparecem na página.
            3. Descreva uma REGRA DE EXTRAÇÃO DEFINITIVA (Contrato).
               Ex: "Cada transação é um bloco. A data está no início da linha, a descrição ocupa as duas linhas seguintes e o valor está à extrema direita da primeira linha do bloco."
            4. Retorne o contrato detalhado e o número de linhas lógicas por registro.`

            : `VOCÊ É UM EXTRATOR DE PADRÕES ESTRUTURAIS LATERAIS.
            Mapeie os índices de colunas (0 a N) baseando-se na correção:
            BRUTO: "${learnedPatternSource.originalRaw.join(' ; ')}"
            GABARITO: Data: "${learnedPatternSource.corrected.date}", Nome: "${learnedPatternSource.corrected.description}", Valor: "${learnedPatternSource.corrected.amount}"`;

            const contents: any = { parts: [] };

            if (isBlockMode && rawBase64) {
                contents.parts.push({
                    inlineData: {
                        data: rawBase64,
                        mimeType: 'application/pdf'
                    }
                });
            }

            contents.parts.push({ text: instruction });

            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: contents,
                config: { 
                    temperature: 0,
                    responseMimeType: "application/json",
                    responseSchema: isBlockMode ? {
                        type: Type.OBJECT,
                        properties: {
                            blockRecipe: { type: Type.STRING },
                            linesPerRecord: { type: Type.INTEGER }
                        },
                        required: ["blockRecipe", "linesPerRecord"]
                    } : {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            setActiveMapping((prev: any) => {
                if (isBlockMode) {
                    return {
                        ...prev,
                        extractionMode: 'BLOCK',
                        blockContract: `CONTRATO DE EXTRAÇÃO: ${result.blockRecipe}`,
                        dateColumnIndex: -1,
                        descriptionColumnIndex: -1,
                        amountColumnIndex: -1
                    };
                }

                const newIgnored = Array.from(new Set([
                    ...(prev.ignoredKeywords || []), 
                    ...(result.ignoredKeywords || [])
                ].map(k => k.trim().toUpperCase()))).filter(k => k.length >= 2);

                return {
                    ...prev,
                    extractionMode: 'COLUMNS',
                    dateColumnIndex: result.dateColumnIndex,
                    descriptionColumnIndex: result.descriptionColumnIndex,
                    amountColumnIndex: result.amountColumnIndex,
                    ignoredKeywords: newIgnored
                };
            });
            showToast("O padrão foi aprendido com sucesso!", "success");
        } catch (e: any) {
            console.error("[PatternTeacher] Fail:", e);
            showToast("Erro ao aprender o padrão.", "error");
        } finally {
            setIsInferringMapping(false);
            setLearnedPatternSource(null);
        }
    }, [learnedPatternSource, rawBase64, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

