                ) : <span className="text-[10px] text-slate-400 italic mt-0.5">Nenhum arquivo</span>}
            </div>

            <div className="flex items-center gap-2">
                {ctrl.isUploading ? (
                    <svg className="animate-spin h-5 w-5 text-blue-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                ) : !isUploaded ? (
                    <button onClick={() => ctrl.triggerUpload('replace')} className="px-4 py-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-600 hover:border-brand-blue hover:text-brand-blue rounded-lg text-xs font-bold uppercase tracking-wide shadow-sm transition-all">{t('upload.statementButton')}</button>
                ) : (
                    <button onClick={() => ctrl.setIsMenuOpen(!ctrl.isMenuOpen)} className={`p-2 rounded-full transition-all border ${ctrl.isMenuOpen ? 'bg-blue-50 border-blue-200 text-brand-blue' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200'}`}><EllipsisVerticalIcon className="w-5 h-5" /></button>
                )}

                {ctrl.isMenuOpen && createPortal(
                    <BankManagerMenu 
                        menuRef={ctrl.menuRef}
                        menuPos={ctrl.menuPos}
                        onMouseDown={ctrl.handleMouseDown}
                        onClose={() => ctrl.setIsMenuOpen(false)}
                        onTriggerUpload={ctrl.triggerUpload}
                        bankFiles={ctrl.bankFiles}
                        onRemoveSpecific={ctrl.removeSpecificFile}
                        onRemoveAll={() => { removeBankStatementFile(bank.id); ctrl.setIsMenuOpen(false); }}
                    />, document.body
                )}
            </div>
        </div>
    );
};

import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
    rawBase64?: string; 
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast,
    rawBase64
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async (extractionMode: 'COLUMNS' | 'BLOCK' = 'COLUMNS') => {
        if (!learnedPatternSource) return;

        setIsInferringMapping(true);
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            const isBlockMode = extractionMode === 'BLOCK';

            const instruction = isBlockMode 
            ? `VOCÊ É UM ANALISTA DE PADRÕES REPETITIVOS. 
            Estou te enviando um PDF e uma AMOSTRA MESTRE de como uma transação deve ser extraída.

            AMOSTRA MESTRE (O GABARITO):
            - Texto Bruto no Documento: "${learnedPatternSource.originalRaw.join(' | ')}"
            - Como deve virar (Data): "${learnedPatternSource.corrected.date}"
            - Como deve virar (Descrição): "${learnedPatternSource.corrected.description}"
            - Como deve virar (Valor): "${learnedPatternSource.corrected.amount}"

            SUA MISSÃO:
            1. Olhe o PDF e localize EXATAMENTE onde essa Amostra Mestre está (coordenadas e vizinhança).
            2. Crie uma REGRA ALGORÍTMICA RÍGIDA baseada na posição visual e sequência de strings.
            3. Ignore o significado das palavras. Foque no "DNA ESTRUTURAL".
            4. Retorne o "blockRecipe" descrevendo o passo-a-passo mecânico para achar as próximas.`

            : `VOCÊ É UM EXTRATOR DE ÍNDICES.
            Determine as colunas baseando-se NESTA correção:
            BRUTO: "${learnedPatternSource.originalRaw.join(' ; ')}"
            GABARITO: Data: "${learnedPatternSource.corrected.date}", Nome: "${learnedPatternSource.corrected.description}", Valor: "${learnedPatternSource.corrected.amount}"`;

            const contents: any = { parts: [] };

            if (isBlockMode && rawBase64) {
                contents.parts.push({
                    inlineData: {
                        data: rawBase64,
                        mimeType: 'application/pdf'
                    }
                });
            }

            contents.parts.push({ text: instruction });

            const response = await ai.models.generateContent({
                model: 'gemini-3-pro-preview',
                contents: contents,
                config: { 
                    temperature: 0,
                    responseMimeType: "application/json",
                    responseSchema: isBlockMode ? {
                        type: Type.OBJECT,
                        properties: {
                            blockRecipe: { type: Type.STRING },
                            linesPerRecord: { type: Type.INTEGER }
                        },
                        required: ["blockRecipe", "linesPerRecord"]
                    } : {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            setActiveMapping((prev: any) => {
                if (isBlockMode) {
                    return {
                        ...prev,
                        extractionMode: 'BLOCK',
                        blockContract: `AMOSTRA MESTRE: ${learnedPatternSource.originalRaw.join(' | ')}. REGRA: ${result.blockRecipe}`,
                        dateColumnIndex: -1,
                        descriptionColumnIndex: -1,
                        amountColumnIndex: -1
                    };
                }

                return {
                    ...prev,
                    extractionMode: 'COLUMNS',
                    dateColumnIndex: result.dateColumnIndex,
                    descriptionColumnIndex: result.descriptionColumnIndex,
                    amountColumnIndex: result.amountColumnIndex,
                    ignoredKeywords: result.ignoredKeywords || []
                };
            });
            showToast("O padrão foi aprendido com sucesso!", "success");
        } catch (e: any) {
            console.error("[PatternTeacher] Fail:", e);
