import { useState, useCallback } from 'react';
import { GoogleGenAI, Type } from "@google/genai";
import { FileModel, Transaction } from '../types';

interface UseAIPatternTeacherProps {
    gridData: string[][];
    setGridData: (data: string[][]) => void;
    setActiveMapping: (mapping: any) => void;
    showToast: (msg: string, type: 'success' | 'error') => void;
    fullFileText?: string;
    rawBase64?: string; 
}

export const useAIPatternTeacher = ({
    gridData,
    setGridData,
    setActiveMapping,
    showToast,
    fullFileText,
    rawBase64
}: UseAIPatternTeacherProps) => {
    const [isInferringMapping, setIsInferringMapping] = useState(false);
    const [learnedPatternSource, setLearnedPatternSource] = useState<{ originalRaw: string[], corrected: any } | null>(null);

    const handleApplyCorrectionPattern = useCallback(async (extractionMode: 'COLUMNS' | 'BLOCK' = 'COLUMNS') => {
        if (!learnedPatternSource) return;

        setIsInferringMapping(true);
        // Usamos Flash para ensinar o padrão para maior velocidade e estabilidade de cota
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY as string });

        try {
            const isBlockMode = extractionMode === 'BLOCK';

            const instruction = isBlockMode 
            ? `VOCÊ É UM ANALISTA DE PADRÕES REPETITIVOS. 
            Estou te enviando um documento e uma AMOSTRA MESTRE de como uma transação deve ser extraída.

            AMOSTRA MESTRE (O GABARITO):
            - Texto Bruto no Documento: "${learnedPatternSource.originalRaw.join(' | ')}"
            - Como deve virar (Data): "${learnedPatternSource.corrected.date}"
            - Como deve virar (Descrição): "${learnedPatternSource.corrected.description}"
            - Como deve virar (Valor): "${learnedPatternSource.corrected.amount}"

            SUA MISSÃO:
            1. Analise o documento e localize onde essa Amostra Mestre está.
            2. Crie uma REGRA ALGORÍTMICA RÍGIDA baseada na posição visual e sequência de strings.
            3. Ignore o significado das palavras. Foque no "DNA ESTRUTURAL".
            4. Retorne o "blockRecipe" descrevendo o passo-a-passo mecânico para achar as próximas transações similares.`

            : `VOCÊ É UM EXTRATOR DE ÍNDICES.
            Determine as colunas baseando-se NESTA correção que o humano fez:
            BRUTO: "${learnedPatternSource.originalRaw.join(' ; ')}"
            GABARITO: Data: "${learnedPatternSource.corrected.date}", Nome: "${learnedPatternSource.corrected.description}", Valor: "${learnedPatternSource.corrected.amount}"
            Retorne os índices de 0 a N.`;

            const contents: any = { parts: [] };

            // Prioridade para o binário (Visão), mas fallback para o snippet de texto se o binário faltar
            if (isBlockMode && rawBase64) {
                contents.parts.push({
                    inlineData: {
                        data: rawBase64,
                        mimeType: 'application/pdf'
                    }
                });
            } else if (fullFileText) {
                contents.parts.push({ text: `CONTEÚDO DO DOCUMENTO:\n${fullFileText.substring(0, 10000)}` });
            }

            contents.parts.push({ text: instruction });

            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: contents,
                config: { 
                    temperature: 0,
                    responseMimeType: "application/json",
                    responseSchema: isBlockMode ? {
                        type: Type.OBJECT,
                        properties: {
                            blockRecipe: { type: Type.STRING },
                            linesPerRecord: { type: Type.INTEGER }
                        },
                        required: ["blockRecipe", "linesPerRecord"]
                    } : {
                        type: Type.OBJECT,
                        properties: {
                            dateColumnIndex: { type: Type.INTEGER },
                            descriptionColumnIndex: { type: Type.INTEGER },
                            amountColumnIndex: { type: Type.INTEGER },
                            ignoredKeywords: { type: Type.ARRAY, items: { type: Type.STRING } }
                        },
                        required: ["dateColumnIndex", "descriptionColumnIndex", "amountColumnIndex", "ignoredKeywords"]
                    }
                }
            });

            const result = JSON.parse(response.text || "{}");

            setActiveMapping((prev: any) => {
                if (isBlockMode) {
                    return {
                        ...prev,
                        extractionMode: 'BLOCK',
                        blockContract: `AMOSTRA MESTRE: ${learnedPatternSource.originalRaw.join(' | ')}. REGRA: ${result.blockRecipe}`,
                        dateColumnIndex: -1,
                        descriptionColumnIndex: -1,
                        amountColumnIndex: -1
                    };
                }

                return {
                    ...prev,
                    extractionMode: 'COLUMNS',
                    dateColumnIndex: result.dateColumnIndex,
                    descriptionColumnIndex: result.descriptionColumnIndex,
                    amountColumnIndex: result.amountColumnIndex,
                    ignoredKeywords: result.ignoredKeywords || []
                };
            });
            showToast("O padrão foi aprendido com sucesso!", "success");
        } catch (e: any) {
            console.error("[PatternTeacher] Fail:", e);
            const errorMsg = e.message || "";
            if (errorMsg.includes("429") || errorMsg.includes("RESOURCE_EXHAUSTED")) {
                showToast("A IA está ocupada. Aguarde 10 segundos e tente novamente.", "error");
            } else {
                showToast("Erro ao aprender o padrão estrutural.", "error");
            }
        } finally {
            setIsInferringMapping(false);
            setLearnedPatternSource(null);
        }
    }, [learnedPatternSource, rawBase64, fullFileText, setActiveMapping, showToast]);

    return {
        isInferringMapping,
        learnedPatternSource,
        setLearnedPatternSource,
        handleApplyCorrectionPattern
    };
};

